    /// Create an active (selectable) suggestion
    pub fn new(text: String) -> Self {
        Self {
            text,
            description: None,
            value: None,
            disabled: false,
            keybinding: None,
            source: None,
        }
    }

    /// Create a disabled (greyed-out) suggestion used for hints or errors
