1	//! Internationalization (i18n) support for Fresh Editor
2	//!
3	//! This module provides locale detection and translation support using rust-i18n.
4	//! Translations are embedded at compile time from JSON files in the `locales/` directory.
5	//!
6	//! # Usage
7	//!
8	//! ```rust
9	//! use rust_i18n::t;
10	//!
11	//! // Simple translation
12	//! let msg = t!("search.no_text");
13	//!
14	//! // Translation with interpolation
15	//! let msg = t!("file.saved_as", path = "/path/to/file");
16	//! ```
