24	/// Type alias for the nested plugin strings map.
25	/// Structure: plugin_name -> locale -> key -> translated_string
26	type PluginStringsMap = HashMap<String, HashMap<String, HashMap<String, String>>>;
27	
28	static PLUGIN_STRINGS: Lazy<RwLock<PluginStringsMap>> = Lazy::new(|| RwLock::new(HashMap::new()));
29	
30	/// Register strings for a plugin.
