                let new_pos = if cursor.deselect_on_move {
                    if let Some(range) = cursor.selection_range() {
                        range.start
                    } else {
                        let p = state.buffer.prev_grapheme_boundary(cursor.position);
                        adjust_position_for_crlf_left(&state.buffer, p)
                    }
                } else {
